SELECT motos1.marca AS datoscopia,   SUM(motos1.inversionus) AS temptc26225288700,   SUM(motos1.inversionus) AS sumcalculation0061002123102817ok,   CAST(EXTRACT(YEAR FROM motos1.fecha) AS BIGINT) AS yrfechaok FROM motos1 WHERE ((CAST(EXTRACT(YEAR FROM motos1.fecha) AS BIGINT) >= 2010) AND (CAST(EXTRACT(YEAR FROM motos1.fecha) AS BIGINT) <= 2015) AND (motos1.categoria = 'MOTOCICLETAS')) GROUP BY motos1.marca,   yrfechaok;
